5	export function InstrumentPanel(): React.JSX.Element {
6	  const selectedTrackIds = useDawStore((s) => s.selectedTrackIds);
7	  const tracks = useDawStore((s) => s.tracks);
8	  const selectedTrack = tracks.find((t) => selectedTrackIds.includes(t.id));
9	
10	  if (selectedTrack?.type === "instrument") {
11	    return (
12	      <section
13	        data-testid="instrument-panel"
14	        className={styles["instrumentPanelFull"]}
15	      >
16	        <SynthEditor trackId={selectedTrack.id} />
17	      </section>
18	    );
19	  }
20	
21	  return (
22	    <section
23	      data-testid="instrument-panel"
24	      className={styles["instrumentPanel"]}
25	    >
26	      {selectedTrack ? "AUDIO TRACK" : "INSTRUMENT"}
27	    </section>
28	  );
29	}
