1	import { useCallback, useState } from "react";
2	import { useTransport } from "@audio/use-transport";
3	import { useDawStore } from "@state/index";
4	import { BpmInput } from "./BpmInput";
5	import { CursorDisplay } from "./CursorDisplay";
6	import styles from "./TransportBar.module.css";
7	
8	export function TransportBar(): React.JSX.Element {
9	  const transport = useTransport();
10	  const transportState = useDawStore((s) => s.transportState);
11	  const bpm = useDawStore((s) => s.bpm);
12	  const loopEnabled = useDawStore((s) => s.loopEnabled);
13	  const setLoop = useDawStore((s) => s.setLoop);
14	  const [metronomeOn, setMetronomeOn] = useState(false);
15	
16	  const handleLoopToggle = useCallback((): void => {
17	    setLoop(!loopEnabled);
18	  }, [loopEnabled, setLoop]);
19	
20	  const handleMetronomeToggle = useCallback((): void => {
21	    const next = !metronomeOn;
22	    setMetronomeOn(next);
23	    transport.setMetronomeEnabled(next);
24	  }, [metronomeOn, transport]);
25	
26	  const handleBpmChange = useCallback(
27	    (newBpm: number): void => {
28	      transport.setBpm(newBpm);
29	    },
30	    [transport],
31	  );
32	
33	  const isPlaying = transportState === "playing";
34	  const clock = transport.getClock();
35	  const tempoMap = clock?.getTempoMap() ?? null;
36	
37	  return (
38	    <header data-testid="toolbar" className={styles["transportBar"]}>
39	      <span className={styles["brand"]}>BRUTALWAV</span>
40	      <div className={styles["spacer"]} />
41	
42	      <div className={styles["controls"]}>
43	        <span className={styles["label"]}>BPM</span>
44	        <BpmInput value={bpm} onChange={handleBpmChange} />
45	
46	        <span className={styles["label"]}>4/4</span>
47	
48	        <button
49	          type="button"
50	          className={styles["transportBtn"]}
51	          aria-pressed={isPlaying}
52	          aria-label="Play"
53	          onClick={() => {
54	            transport.play();
55	          }}
56	        >
57	          {"\u25B6"}
58	        </button>
59	
60	        <button
61	          type="button"
62	          className={styles["transportBtn"]}
63	          aria-label="Stop"
64	          onClick={() => {
65	            transport.stop();
66	          }}
67	        >
68	          {"\u25A0"}
69	        </button>
70	
71	        <CursorDisplay
72	          transportSAB={transport.getTransportSAB()}
73	          tempoMap={tempoMap}
74	        />
75	
76	        <button
77	          type="button"
78	          role="switch"
79	          aria-checked={loopEnabled}
80	          aria-label="Loop"
81	          className={styles["transportBtn"]}
82	          data-active={loopEnabled}
83	          onClick={handleLoopToggle}
84	        >
85	          LOOP
86	        </button>
87	
88	        <div className={styles["metronomeToggle"]}>
89	          <button
90	            type="button"
91	            role="switch"
92	            aria-checked={metronomeOn}
93	            aria-label="Metronome"
94	            className={styles["transportBtn"]}
95	            data-active={metronomeOn}
96	            onClick={handleMetronomeToggle}
97	          >
98	            MET
99	          </button>
100	        </div>
101	      </div>
102	
103	      <span
104	        className={styles["shortcutHint"]}
105	        title="Keyboard Shortcuts (Shift+?)"
106	      >
107	        ?
108	      </span>
109	    </header>
110	  );
111	}
