1	/**
2	 * Types and constants for the TR-808 drum machine.
3	 * Sample-based playback (NOT analog synthesis, per advisory P0-5).
4	 *
5	 * Exports: DrumKit, DrumPattern, DrumTrigger (as specified by epic).
6	 * EARS: R-EVT-12, R-STA-06
7	 */
8	
9	import type { MixerEngine } from "@audio/mixer/types";
10	
11	// ─── Instrument IDs ───
12	
13	export type DrumInstrumentId =
14	  | "bd" // bass drum
15	  | "sd" // snare
16	  | "lt" // low tom
17	  | "mt" // mid tom
18	  | "ht" // high tom
19	  | "rs" // rimshot
20	  | "cp" // clap
21	  | "cb" // cowbell
22	  | "oh" // open hi-hat
23	  | "ch" // closed hi-hat
24	  | "cy"; // cymbal
25	
26	export type DrumInstrumentInfo = {
27	  readonly id: DrumInstrumentId;
28	  readonly label: string;
29	};
30	
31	export const DRUM_INSTRUMENTS: readonly DrumInstrumentInfo[] = [
32	  { id: "bd", label: "Bass Drum" },
33	  { id: "sd", label: "Snare" },
34	  { id: "lt", label: "Low Tom" },
35	  { id: "mt", label: "Mid Tom" },
36	  { id: "ht", label: "High Tom" },
37	  { id: "rs", label: "Rimshot" },
38	  { id: "cp", label: "Clap" },
39	  { id: "cb", label: "Cowbell" },
40	  { id: "oh", label: "Open HH" },
41	  { id: "ch", label: "Closed HH" },
42	  { id: "cy", label: "Cymbal" },
43	] as const;
44	
45	// ─── Per-instrument parameters ───
46	
47	export type DrumInstrumentParams = {
48	  /** BiquadFilter cutoff frequency (200..20000 Hz) */
49	  tone: number;
50	  /** Amplitude envelope release / decay time (0.01..2 s) */
51	  decay: number;
52	  /** AudioBufferSourceNode playbackRate (0.5..2) */
53	  tune: number;
54	  /** GainNode gain (0..1) */
55	  volume: number;
56	};
57	
58	export const PARAM_RANGES: Record<
59	  keyof DrumInstrumentParams,
60	  { min: number; max: number }
61	> = {
62	  tone: { min: 200, max: 20000 },
63	  decay: { min: 0.01, max: 2 },
64	  tune: { min: 0.5, max: 2 },
65	  volume: { min: 0, max: 1 },
66	};
67	
68	export const DEFAULT_INSTRUMENT_PARAMS: Record<
69	  DrumInstrumentId,
70	  DrumInstrumentParams
71	> = {
72	  bd: { tone: 1000, decay: 0.5, tune: 1.0, volume: 0.9 },
73	  sd: { tone: 5000, decay: 0.3, tune: 1.0, volume: 0.8 },
74	  lt: { tone: 800, decay: 0.4, tune: 0.8, volume: 0.7 },
75	  mt: { tone: 1200, decay: 0.35, tune: 1.0, volume: 0.7 },
76	  ht: { tone: 2000, decay: 0.3, tune: 1.2, volume: 0.7 },
77	  rs: { tone: 8000, decay: 0.1, tune: 1.0, volume: 0.6 },
78	  cp: { tone: 3000, decay: 0.4, tune: 1.0, volume: 0.75 },
79	  cb: { tone: 6000, decay: 0.15, tune: 1.0, volume: 0.6 },
80	  oh: { tone: 10000, decay: 0.5, tune: 1.0, volume: 0.7 },
81	  ch: { tone: 10000, decay: 0.08, tune: 1.0, volume: 0.7 },
82	  cy: { tone: 12000, decay: 1.0, tune: 1.0, volume: 0.5 },
83	};
84	
85	// ─── Pattern types ───
86	
87	/** Per-step trigger map: which instruments fire on this step */
88	export type DrumStep = {
89	  readonly triggers: Record<DrumInstrumentId, boolean>;
90	  readonly accent: boolean;
91	  /** Flam offset in milliseconds (0 = no flam) */
92	  readonly flamMs: number;
93	};
94	
95	/** A 16-step pattern */
96	export type DrumPattern = {
97	  readonly name: string;
98	  readonly steps: readonly DrumStep[];
99	};
100	
101	/** A scheduled drum trigger event */
102	export type DrumTrigger = {
103	  readonly instrumentId: DrumInstrumentId;
104	  readonly time: number;
105	  readonly velocity: number;
106	  readonly flamMs?: number;
107	};
108	
109	// ─── DrumKit interface ───
110	
111	export type DrumKit = {
112	  /** Trigger a drum instrument at the given time */
113	  trigger(
114	    instrumentId: DrumInstrumentId,
115	    time: number,
116	    velocity: number,
117	    flamMs?: number,
118	  ): void;
119	  /** Set a parameter on an instrument */
120	  setParam(
121	    instrumentId: DrumInstrumentId,
122	    key: keyof DrumInstrumentParams,
123	    value: number,
124	  ): void;
125	  /** Connect output to mixer channel strip */
126	  connectToMixer(mixer: MixerEngine, trackId: string): void;
127	  /** Disconnect from mixer */
128	  disconnectFromMixer(mixer: MixerEngine, trackId: string): void;
129	  /** Clean up all resources */
130	  dispose(): void;
131	};
132	
133	// ─── Factory helpers ───
134	
135	function createEmptyStep(): DrumStep {
136	  return {
137	    triggers: {
138	      bd: false,
139	      sd: false,
140	      lt: false,
141	      mt: false,
142	      ht: false,
143	      rs: false,
144	      cp: false,
145	      cb: false,
146	      oh: false,
147	      ch: false,
148	      cy: false,
149	    },
150	    accent: false,
151	    flamMs: 0,
152	  };
153	}
154	
155	export function createEmptyPattern(name = "A"): DrumPattern {
156	  const steps: DrumStep[] = [];
157	  for (let i = 0; i < 16; i++) {
158	    steps.push(createEmptyStep());
159	  }
160	  return { name, steps };
161	}
