64	            color={track.color}
65	            volume={track.volume}
66	            pan={track.pan}
67	            muted={track.muted}
68	            solo={track.solo}
69	            meterLevel={meters.channels[track.id]?.level ?? 0}
70	            meterPeak={meters.channels[track.id]?.peak ?? 0}
71	            clipping={meters.channels[track.id]?.clipping ?? false}
72	            onVolumeChange={handleVolumeChange}
73	            onPanChange={handlePanChange}
74	            onMuteToggle={handleMuteToggle}
75	            onSoloToggle={handleSoloToggle}
76	          />
77	        ))
78	      )}
79	      <MasterStrip
80	        volume={masterVolume}
81	        meterLevel={meters.master.level}
82	        meterPeak={meters.master.peak}
83	        clipping={meters.master.clipping}
84	        onVolumeChange={setMasterVolume}
85	      />
86	    </section>
87	  );
88	}
