      <span
        style={{
          fontFamily: tokens.font.mono,
          fontSize: tokens.text["2xs"],
          color: tokens.color.gray300,
        }}
      >
        {label}
      </span>
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(e) => {
          onChange(Number(e.target.value));
        }}
        style={{ width: 48, accentColor: tokens.color.amber }}
        aria-label={label}
      />
    </div>
  );
}

function InstrumentRow({
  instrumentId,
  instrumentLabel,
  steps,
  currentStep,
  params,
  onToggle,
  onTriggerPad,
  onParamChange,
}: {
  instrumentId: DrumInstrumentId;
  instrumentLabel: string;
  steps: DrumPattern["steps"];
  currentStep: number;
  params: DrumInstrumentParams;
  onToggle: (step: number) => void;
  onTriggerPad: () => void;
  onParamChange: (key: keyof DrumInstrumentParams, value: number) => void;
}): React.JSX.Element {
  const [focusedStep, setFocusedStep] = useState(0);
  const stepRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const handleArrowNav = useCallback(
    (index: number, direction: -1 | 1) => {
      const next = index + direction;
      if (next >= 0 && next < steps.length) {
        setFocusedStep(next);
        stepRefs.current[next]?.focus();
      }
    },
    [steps.length],
  );

