    // Audio triggering handled by audio layer
  }, []);

  const onParamChange = useCallback(
    (
      instrumentId: DrumInstrumentId,
      key: keyof DrumInstrumentParams,
      value: number,
    ) => {
      setParams((prev) => ({
        ...prev,
        [instrumentId]: { ...prev[instrumentId], [key]: value },
      }));
