import { useCallback, useRef, useState } from "react";
import { useDawStore } from "@state/store";
import { SynthEditor } from "@ui/synth";
import { DrumMachinePanel } from "@ui/drum-machine";
import { createStepSequencer, type StepSequencer } from "@audio/drum-machine/step-sequencer";
import { createDrumKit, type DrumKit } from "@audio/drum-machine/drum-kit";
import { useTransport } from "@audio/use-transport";
import {
  DRUM_INSTRUMENTS,
  DEFAULT_PARAMS,
  type DrumInstrumentId,
  type DrumInstrumentParams,
  type DrumPattern,
} from "@audio/drum-machine/drum-types";
import styles from "./panels.module.css";

function DrumMachineController({
  trackId: _trackId,
}: {
  trackId: string;
}): React.JSX.Element {
  const transport = useTransport();
  const transportState = useDawStore((s) => s.transportState);

  const kitRef = useRef<DrumKit | null>(null);
  const seqRef = useRef<StepSequencer | null>(null);
  const stepRef = useRef(0);
  const rafRef = useRef(0);

  const [pattern, setPattern] = useState<DrumPattern>(() => {
    const seq = getOrCreateSequencer();
    return seq.getPattern();
  });
  const [currentStep, setCurrentStep] = useState(0);
  const [params, setParams] = useState<Record<DrumInstrumentId, DrumInstrumentParams>>(
    () => {
      const initial = {} as Record<DrumInstrumentId, DrumInstrumentParams>;
      for (const inst of DRUM_INSTRUMENTS) {
        initial[inst.id] = { ...DEFAULT_PARAMS[inst.id] };
      }
      return initial;
    },
  );

  function getOrCreateKit(): DrumKit {
    if (!kitRef.current) {
      kitRef.current = createDrumKit();
    }
    return kitRef.current;
  }

  function getOrCreateSequencer(): StepSequencer {
    if (!seqRef.current) {
      const kit = getOrCreateKit();
      seqRef.current = createStepSequencer((trigger) => {
        kit.trigger(trigger);
      });
    }
    return seqRef.current;
  }

  // Transport sync: advance step sequencer when playing
  const prevTransportState = useRef(transportState);
  if (transportState !== prevTransportState.current) {
    prevTransportState.current = transportState;
    if (transportState === "playing") {
      const clock = transport.getClock();
      if (clock) {
        const bpm = useDawStore.getState().bpm;
        const stepsPerBeat = 4; // 16th notes
        const stepDuration = 60 / (bpm * stepsPerBeat);

        const tick = (): void => {
          const cursor = clock.getCursorSeconds();
          const step = Math.floor(cursor / stepDuration) % 16;
          if (step !== stepRef.current) {
            stepRef.current = step;
            const seq = getOrCreateSequencer();
            seq.scheduleStep(step, 0);
            setCurrentStep(step);
          }
          rafRef.current = requestAnimationFrame(tick);
        };
        rafRef.current = requestAnimationFrame(tick);
      }
    } else {
      cancelAnimationFrame(rafRef.current);
      if (transportState === "stopped") {
        stepRef.current = 0;
        setCurrentStep(0);
      }
    }
  }

  const handleToggleStep = useCallback(
    (instrumentId: DrumInstrumentId, stepIndex: number) => {
      const seq = getOrCreateSequencer();
      seq.toggleStep(instrumentId, stepIndex);
      setPattern(seq.getPattern());
    },
    [],
  );

  const handleSetAccent = useCallback(
    (stepIndex: number, accent: boolean) => {
      const seq = getOrCreateSequencer();
      seq.setAccent(stepIndex, accent);
      setPattern(seq.getPattern());
    },
    [],
  );

  const handleTriggerPad = useCallback(
    (instrumentId: DrumInstrumentId) => {
      const kit = getOrCreateKit();
      kit.trigger({ instrumentId, time: 0, velocity: 0.8 });
    },
    [],
  );

  const handleParamChange = useCallback(
    (instrumentId: DrumInstrumentId, key: keyof DrumInstrumentParams, value: number) => {
      setParams((prev) => ({
        ...prev,
        [instrumentId]: { ...prev[instrumentId], [key]: value },
      }));
      const kit = getOrCreateKit();
      kit.setParam(instrumentId, key, value);
    },
    [],
  );

  const handleSwitchPattern = useCallback(
    (name: string) => {
      const seq = getOrCreateSequencer();
      seq.switchPattern(name);
      setPattern(seq.getPattern());
    },
    [],
  );

  const handleClearPattern = useCallback(() => {
    const seq = getOrCreateSequencer();
    seq.clearPattern();
    setPattern(seq.getPattern());
  }, []);

  return (
    <DrumMachinePanel
      pattern={pattern}
      currentStep={currentStep}
      activePatternName={pattern.name}
      onToggleStep={handleToggleStep}
      onSetAccent={handleSetAccent}
      onTriggerPad={handleTriggerPad}
      onParamChange={handleParamChange}
      onSwitchPattern={handleSwitchPattern}
      onClearPattern={handleClearPattern}
      params={params}
    />
  );
}

export function InstrumentPanel(): React.JSX.Element {
  const selectedTrackIds = useDawStore((s) => s.selectedTrackIds);
  const tracks = useDawStore((s) => s.tracks);
  const selectedTrack = tracks.find((t) => selectedTrackIds.includes(t.id));

  if (selectedTrack?.type === "instrument") {
    return (
      <section
        data-testid="instrument-panel"
        className={styles["instrumentPanelFull"]}
      >
        <SynthEditor trackId={selectedTrack.id} />
      </section>
    );
  }

  if (selectedTrack?.type === "drum") {
    return (
      <section
        data-testid="instrument-panel"
        className={styles["instrumentPanelFull"]}
      >
        <DrumMachineController trackId={selectedTrack.id} />
      </section>
    );
  }

  return (
    <section
      data-testid="instrument-panel"
      className={styles["instrumentPanel"]}
    >
      {selectedTrack ? "AUDIO TRACK" : "Select a track"}
    </section>
  );
}

